// App State
let currentTab = "games";
let entertainmentList = [];
let currentUser = null;
let authMode = "login"; // "login" or "signup"

// Auth Screen Toggling
function showAuthScreen() {
    document.getElementById("app-container").style.display = "none";
    document.getElementById("auth-container").style.display = "flex";
    document.getElementById("auth-error-msg").style.display = "none";
    document.getElementById("auth-form").reset();
    setAuthMode("login");
}

function showAppScreen(user) {
    document.getElementById("auth-container").style.display = "none";
    document.getElementById("app-container").style.display = "block";
    document.getElementById("user-email-display").innerText = user.email;
}

function setAuthMode(mode) {
    authMode = mode;
    const subtitle = document.getElementById("auth-subtitle");
    const submitBtn = document.getElementById("auth-submit-btn");
    const toggleLink = document.getElementById("auth-toggle-link");
    const toggleText = toggleLink.parentNode;
    const errorDiv = document.getElementById("auth-error-msg");
    
    errorDiv.style.display = "none";
    
    if (authMode === "login") {
        subtitle.innerText = "Log in to manage your private gaming logs & watch lists";
        submitBtn.innerText = "Log In";
        toggleText.innerHTML = `Don't have an account? <a href="#" id="auth-toggle-link" style="color: var(--accent-color); text-decoration: none; font-weight: 600;">Sign Up</a>`;
    } else {
        subtitle.innerText = "Create a new account to sync your lists across devices";
        submitBtn.innerText = "Create Account";
        toggleText.innerHTML = `Already have an account? <a href="#" id="auth-toggle-link" style="color: var(--accent-color); text-decoration: none; font-weight: 600;">Log In</a>`;
    }
    
    // Re-attach listener since we modified innerHTML
    document.getElementById("auth-toggle-link").addEventListener("click", (e) => {
        e.preventDefault();
        setAuthMode(authMode === "login" ? "signup" : "login");
    });
}

// Attach initial auth toggle listener
document.getElementById("auth-toggle-link").addEventListener("click", (e) => {
    e.preventDefault();
    setAuthMode(authMode === "login" ? "signup" : "login");
});

// Auth Form Submission (Handles both Login and Sign Up)
document.getElementById("auth-form").addEventListener("submit", async (e) => {
    e.preventDefault();
    const email = document.getElementById("auth-email").value.trim();
    const password = document.getElementById("auth-password").value;
    const errorDiv = document.getElementById("auth-error-msg");
    const submitBtn = document.getElementById("auth-submit-btn");
    
    errorDiv.style.display = "none";
    submitBtn.disabled = true;
    
    if (authMode === "login") {
        submitBtn.innerText = "Logging in...";
        const { data, error } = await supabaseClient.auth.signInWithPassword({
            email: email,
            password: password
        });

        if (error) {
            errorDiv.innerText = error.message;
            errorDiv.style.display = "block";
            submitBtn.innerText = "Log In";
            submitBtn.disabled = false;
        }
    } else {
        submitBtn.innerText = "Creating account...";
        const { data, error } = await supabaseClient.auth.signUp({
            email: email,
            password: password
        });

        if (error) {
            errorDiv.innerText = error.message;
            errorDiv.style.display = "block";
            submitBtn.innerText = "Create Account";
            submitBtn.disabled = false;
        } else {
            alert("Account created successfully! You are now logged in.");
        }
    }
});

document.getElementById("logout-btn").addEventListener("click", async () => {
    await supabaseClient.auth.signOut();
});

// Listen for Auth Changes
supabaseClient.auth.onAuthStateChange(async (event, session) => {
    if (session) {
        currentUser = session.user;
        showAppScreen(currentUser);
        await loadUserData();
    } else {
        currentUser = null;
        entertainmentList = [];
        showAuthScreen();
    }
});

// Database Sync: Load User Items (Auto-populate defaults if empty)
async function loadUserData() {
    if (!currentUser) return;

    const { data, error } = await supabaseClient
        .from("vault_items")
        .select("*");

    if (error) {
        console.error("Error loading user data:", error);
        return;
    }

    if (data && data.length > 0) {
        entertainmentList = data;
        render();
    } else {
        console.log("No data found for user, initializing defaults...");
        const defaults = [...defaultGames, ...defaultAnime].map(item => ({
            id: item.id,
            user_id: currentUser.id,
            title: item.title,
            category: item.category,
            rating: item.rating,
            month: item.month,
            year: item.year,
            image: item.image || "",
            notes: item.notes || ""
        }));

        const { error: insertError } = await supabaseClient
            .from("vault_items")
            .insert(defaults);

        if (insertError) {
            console.error("Error inserting defaults:", insertError);
        } else {
            entertainmentList = defaults;
            render();
        }
    }
}

// Generate Cover Color Gradients based on string hashes
function getGlowStyle(title) {
    let hash = 0;
    for (let i = 0; i < title.length; i++) {
        hash = title.charCodeAt(i) + ((hash << 5) - hash);
    }
    const h1 = Math.abs(hash % 360);
    const h2 = (h1 + 60) % 360;
    return `background: linear-gradient(135deg, hsl(${h1}, 70%, 15%) 0%, hsl(${h2}, 80%, 25%) 100%);`;
}

// Render Cards
function render() {
    const grid = document.getElementById("grid-section");
    const searchQuery = document.getElementById("search-input").value.toLowerCase();
    const yearFilter = document.getElementById("year-filter").value;
    const sortFilter = document.getElementById("sort-filter").value;

    grid.innerHTML = "";

    // Filter items
    let filtered = entertainmentList.filter(item => {
        const matchesTab = item.category === currentTab;
        const matchesSearch = item.title.toLowerCase().includes(searchQuery);
        const matchesYear = yearFilter === "all" ? true : item.year.toString() === yearFilter;
        return matchesTab && matchesSearch && matchesYear;
    });

    // Sorting
    const months = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
    filtered.sort((a, b) => {
        if (sortFilter === "alpha") {
            return a.title.localeCompare(b.title);
        }
        
        const dateWeightA = parseInt(a.year) * 12 + months.indexOf(a.month);
        const dateWeightB = parseInt(b.year) * 12 + months.indexOf(b.month);

        if (sortFilter === "newest") {
            return dateWeightB - dateWeightA;
        } else {
            return dateWeightA - dateWeightB;
        }
    });

    // Build Cards
    filtered.forEach(item => {
        const card = document.createElement("div");
        card.className = "card";
        
        let stars = "⭐".repeat(item.rating);
        
        let imageHtml = "";
        if (item.image) {
            imageHtml = `<img src="${item.image}" class="card-img" alt="${item.title}" onerror="this.style.display='none'; this.nextElementSibling.style.display='flex';">`;
        }
        
        const style = getGlowStyle(item.title);
        
        card.innerHTML = `
            <div class="card-img-container" style="${style}">
                ${imageHtml}
                <div class="card-fallback" style="display: ${item.image ? 'none' : 'flex'}">
                    ${item.title.substring(0, 2).toUpperCase()}
                </div>
                <div class="card-date-badge">${item.month} ${item.year}</div>
            </div>
            <div class="card-content">
                <h3 class="card-title">${item.title}</h3>
                <div class="card-rating">${stars}</div>
                <p class="card-notes">${item.notes || 'No review notes written yet.'}</p>
                <div class="card-actions">
                    <button class="btn btn-secondary btn-edit" data-id="${item.id}">✏️ Edit</button>
                    <button class="btn btn-danger btn-delete" data-id="${item.id}">🗑️ Delete</button>
                </div>
            </div>
        `;
        grid.appendChild(card);
    });

    if (filtered.length === 0) {
        const placeholder = document.createElement("div");
        placeholder.style.gridColumn = "1 / -1";
        placeholder.style.textAlign = "center";
        placeholder.style.padding = "50px 0";
        placeholder.style.color = "var(--text-secondary)";
        placeholder.innerHTML = `<h3 style="margin-bottom:10px;">No items found</h3><p>Try resetting filters or adding a new entry!</p>`;
        grid.appendChild(placeholder);
    }

    // Attach card event listeners
    document.querySelectorAll(".btn-delete").forEach(btn => {
        btn.addEventListener("click", async (e) => {
            const id = e.target.getAttribute("data-id");
            if (confirm("Are you sure you want to delete this item?")) {
                const deleteBtn = e.target;
                deleteBtn.disabled = true;
                deleteBtn.innerText = "Deleting...";

                const { error } = await supabaseClient
                    .from("vault_items")
                    .delete()
                    .eq("id", id)
                    .eq("user_id", currentUser.id);

                if (error) {
                    alert("Error deleting item: " + error.message);
                    deleteBtn.disabled = false;
                    deleteBtn.innerText = "🗑️ Delete";
                } else {
                    entertainmentList = entertainmentList.filter(item => item.id !== id);
                    render();
                }
            }
        });
    });

    document.querySelectorAll(".btn-edit").forEach(btn => {
        btn.addEventListener("click", (e) => {
            const id = e.target.getAttribute("data-id");
            const item = entertainmentList.find(item => item.id === id);
            if (item) {
                openModal(item);
            }
        });
    });
}

// Modal handling and Image Upload Compression
const modal = document.getElementById("item-modal");
const closeModal = document.querySelector(".close-modal");
let uploadedImageBase64 = "";

function updatePreview(src) {
    const previewGroup = document.getElementById("image-preview-group");
    const previewImg = document.getElementById("modal-image-preview");
    if (src) {
        previewImg.src = src;
        previewGroup.style.display = "block";
    } else {
        previewGroup.style.display = "none";
        previewImg.src = "";
    }
}

document.getElementById("form-image-file").addEventListener("change", (e) => {
    const file = e.target.files[0];
    if (!file) {
        uploadedImageBase64 = "";
        updatePreview(document.getElementById("form-image").value.trim());
        return;
    }

    const reader = new FileReader();
    reader.onload = function(event) {
        const img = new Image();
        img.onload = function() {
            const canvas = document.createElement("canvas");
            const ctx = canvas.getContext("2d");
            
            let width = img.width;
            let height = img.height;
            const maxDim = 400;
            
            if (width > height) {
                if (width > maxDim) {
                    height = Math.round(height * (maxDim / width));
                    width = maxDim;
                }
            } else {
                if (height > maxDim) {
                    width = Math.round(width * (maxDim / height));
                    height = maxDim;
                }
            }
            
            canvas.width = width;
            canvas.height = height;
            ctx.drawImage(img, 0, 0, width, height);
            uploadedImageBase64 = canvas.toDataURL("image/jpeg", 0.7);
            
            document.getElementById("form-image").value = "";
            updatePreview(uploadedImageBase64);
        };
        img.src = event.target.result;
    };
    reader.readAsDataURL(file);
});

document.getElementById("form-image").addEventListener("input", (e) => {
    const val = e.target.value.trim();
    if (val !== "") {
        document.getElementById("form-image-file").value = "";
        uploadedImageBase64 = "";
        updatePreview(val);
    } else {
        updatePreview("");
    }
});

function openModal(editItem = null) {
    modal.style.display = "flex";
    const form = document.getElementById("item-form");
    form.reset();
    uploadedImageBase64 = "";
    updatePreview("");

    if (editItem) {
        document.getElementById("modal-title").innerText = "Edit Item";
        document.getElementById("item-id").value = editItem.id;
        document.getElementById("form-title").value = editItem.title;
        document.getElementById("form-category").value = editItem.category;
        document.getElementById("form-rating").value = editItem.rating;
        document.getElementById("form-month").value = editItem.month;
        document.getElementById("form-year").value = editItem.year.toString();
        
        document.getElementById("form-image").value = editItem.image.startsWith("data:") ? "" : editItem.image;
        uploadedImageBase64 = editItem.image.startsWith("data:") ? editItem.image : "";
        document.getElementById("form-notes").value = editItem.notes;
        
        if (editItem.image) {
            updatePreview(editItem.image);
        }
    } else {
        document.getElementById("modal-title").innerText = "Add New Item";
        document.getElementById("item-id").value = "";
        document.getElementById("form-category").value = currentTab;
    }
}

closeModal.addEventListener("click", () => {
    modal.style.display = "none";
});

window.addEventListener("click", (e) => {
    if (e.target === modal) {
        modal.style.display = "none";
    }
});

// Form Submission Sync with Supabase
document.getElementById("item-form").addEventListener("submit", async (e) => {
    e.preventDefault();
    
    const id = document.getElementById("item-id").value;
    const title = document.getElementById("form-title").value;
    const category = document.getElementById("form-category").value;
    const rating = parseInt(document.getElementById("form-rating").value);
    const month = document.getElementById("form-month").value;
    const year = parseInt(document.getElementById("form-year").value);
    const notes = document.getElementById("form-notes").value;
    
    let image = "";
    if (uploadedImageBase64) {
        image = uploadedImageBase64;
    } else {
        image = document.getElementById("form-image").value.trim();
    }

    const submitBtn = e.target.querySelector("button[type='submit']");
    submitBtn.disabled = true;
    submitBtn.innerText = "Saving...";

    if (id) {
        const { error } = await supabaseClient
            .from("vault_items")
            .update({ title, category, rating, month, year, image, notes })
            .eq("id", id)
            .eq("user_id", currentUser.id);

        if (error) {
            alert("Error updating item: " + error.message);
        } else {
            const idx = entertainmentList.findIndex(item => item.id === id);
            if (idx !== -1) {
                entertainmentList[idx] = { id, user_id: currentUser.id, title, category, rating, month, year, image, notes };
            }
        }
    } else {
        const newId = Date.now().toString();
        const newItem = { id: newId, user_id: currentUser.id, title, category, rating, month, year, image, notes };
        
        const { error } = await supabaseClient
            .from("vault_items")
            .insert([newItem]);

        if (error) {
            alert("Error saving item: " + error.message);
        } else {
            entertainmentList.push(newItem);
        }
    }

    submitBtn.disabled = false;
    submitBtn.innerText = "Save Item";
    modal.style.display = "none";
    render();
});

// Event Listeners for Filters
document.getElementById("search-input").addEventListener("input", render);
document.getElementById("year-filter").addEventListener("change", render);
document.getElementById("sort-filter").addEventListener("change", render);

// Tab switching
document.querySelectorAll(".tab-btn").forEach(btn => {
    btn.addEventListener("click", (e) => {
        document.querySelectorAll(".tab-btn").forEach(b => b.classList.remove("active"));
        e.target.classList.add("active");
        currentTab = e.target.getAttribute("data-tab");
        render();
    });
});

document.getElementById("add-btn").addEventListener("click", () => openModal());

// Export JSON Utility (Client-side formatting)
document.getElementById("export-btn").addEventListener("click", () => {
    const cleanedList = entertainmentList.map(({ id, title, category, rating, month, year, image, notes }) => ({
        id, title, category, rating, month, year, image, notes
    }));
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(cleanedList, null, 4));
    const downloadAnchor = document.createElement('a');
    downloadAnchor.setAttribute("href", dataStr);
    downloadAnchor.setAttribute("download", "game_anime_vault_backup.json");
    document.body.appendChild(downloadAnchor);
    downloadAnchor.click();
    downloadAnchor.remove();
});

// Import JSON Utility Sync with Supabase
const fileInput = document.getElementById("import-file");
document.getElementById("import-btn").addEventListener("click", () => {
    fileInput.click();
});

fileInput.addEventListener("change", async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async function(evt) {
        try {
            const imported = JSON.parse(evt.target.result);
            if (Array.isArray(imported)) {
                const confirmOverwrite = confirm("Do you want to overwrite your current database list? Click OK to overwrite, or Cancel to merge imported items.");
                
                if (confirmOverwrite) {
                    const { error: deleteError } = await supabaseClient
                        .from("vault_items")
                        .delete()
                        .eq("user_id", currentUser.id);
                    
                    if (deleteError) {
                        alert("Error clearing database: " + deleteError.message);
                        return;
                    }
                    
                    const itemsToInsert = imported.map(item => ({
                        id: item.id.startsWith("g") || item.id.startsWith("a") ? item.id + "_" + currentUser.id.substring(0, 5) : item.id,
                        user_id: currentUser.id,
                        title: item.title,
                        category: item.category,
                        rating: item.rating,
                        month: item.month,
                        year: item.year,
                        image: item.image || "",
                        notes: item.notes || ""
                    }));

                    const { error: insertError } = await supabaseClient
                        .from("vault_items")
                        .insert(itemsToInsert);

                    if (insertError) {
                        alert("Error importing items: " + insertError.message);
                    } else {
                        entertainmentList = itemsToInsert;
                        render();
                        alert("Import successful! All items written to cloud.");
                    }
                } else {
                    const itemsToInsert = [];
                    imported.forEach(imp => {
                        if (!entertainmentList.some(item => item.title.toLowerCase() === imp.title.toLowerCase() && item.category === imp.category)) {
                            const newId = "imp_" + Date.now() + "_" + Math.random().toString(36).substring(2, 7);
                            itemsToInsert.push({
                                id: newId,
                                user_id: currentUser.id,
                                title: imp.title,
                                category: imp.category,
                                rating: imp.rating,
                                month: imp.month,
                                year: imp.year,
                                image: imp.image || "",
                                notes: imp.notes || ""
                            });
                        }
                    });

                    if (itemsToInsert.length > 0) {
                        const { error: insertError } = await supabaseClient
                            .from("vault_items")
                            .insert(itemsToInsert);

                        if (insertError) {
                            alert("Error merging items: " + insertError.message);
                        } else {
                            entertainmentList.push(...itemsToInsert);
                            render();
                            alert(`Merged ${itemsToInsert.length} new items into your database!`);
                        }
                    } else {
                        alert("No new items to merge.");
                    }
                }
            } else {
                alert("Invalid format! Import must be a JSON array.");
            }
        } catch (err) {
            alert("Error parsing JSON file: " + err.message);
        }
    };
    reader.readAsText(file);
});
